local LFightIdleBaseCtrl = LXImport(".LFightIdleBaseCtrl")

---@class LFightIdleEffectCtrl:LFightIdleBaseCtrl
local LFightIdleEffectCtrl = LxClass("LFightIdleEffectCtrl",LFightIdleBaseCtrl)
-----------------------------------------------------------------
local LFightIdleConst = LFightIdleConst
local LFightIdleEffect = LXImport("..Object.LFightIdleEffect")
local LFightIdleMask = LXImport("..Object.LFightIdleMask")
-----------------------------------------------------------------
function LFightIdleEffectCtrl:LFightIdleEffectCtrl()
	--所有对象列表{LFightIdleEffect,...}
	---@type LFightIdleEffect[]
	self._effList = {}

	--运行标记
	self._isRunning = false
	--缓存

	self._cacheList = {}

	self._effectIdx = 0

	self._preloadList = {}
	
	self._effMaskObj = nil
end

-----------------------------------------------------------------
---@return LFightIdleEffect
function LFightIdleEffectCtrl:PreloadEffectObject(parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,curTime)
	local idx = self._effectIdx + 1
	self._effectIdx = idx

	local eff = LFightIdleEffect:New(self._manager)
	eff:Create(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,curTime)
	self:AddPreload(eff)
	eff:PreloadEffect()
	return eff
end

function LFightIdleEffectCtrl:AddPreload(eff)
	local effId = eff:GetEffId()
	local curEffList = self._preloadList[effId] or {}
	table.insert(curEffList, eff)
	self._preloadList[effId] = curEffList
end

-----------------------------------------------------------------
function LFightIdleEffectCtrl:MakeEffectObject(parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,curTime)
	if self._isDestroy then
		return
	end
	local idx = self._effectIdx + 1
	self._effectIdx = idx

	---@type LFightIdleEffect
	local obj = LFightIdleEffect:New(self._manager)
	obj:Create(idx,parentTrans,effId,pos,dir,startTime,playTime,dissipateTime,curTime)
	return obj
end

-----------------------------------------------------------------
---@param obj LFightIdleEffect
function LFightIdleEffectCtrl:AddEffect(eff)
	if self._isDestroy then
		return
	end
	if(self._isRunning) then
		table.insert(self._cacheList,{true,eff})
		return
	end

	table.insert(self._effList,eff)
end

function LFightIdleEffectCtrl:RemoveEffect(eff)
	if(self._isRunning) then
		table.insert(self._cacheList,{false,eff})
		return
	end
	table.removeidata(self._effList,eff)
end

-----------------------------------------------------------------
function LFightIdleEffectCtrl:CircleArea(circlePos)
	local effList = self._effList
	for k,v in ipairs(effList) do
		v:CircleArea(circlePos)
	end
end
-----------------------------------------------------------------
function LFightIdleEffectCtrl:InitMask(parentTrans, bInitShow, initPos)
	if self._effMaskObj then
		return
	end
	
	self._effMaskObj = LFightIdleMask:New()
	self._effMaskObj:Create(parentTrans, bInitShow, initPos)
end
function LFightIdleEffectCtrl:ShowMask(bShow)
	if self._effMaskObj then
		local sceneCls = GF.GetNowSceneClass()
		self._effMaskObj:ShowMask(bShow, sceneCls:GetSceneCameraPosition())
	end
end
-----------------------------------------------------------------
function LFightIdleEffectCtrl:OnRun(time)
	self._isRunning = true
	local effList = self._effList
	local delIndexList = {}
	for k,v in ipairs(effList) do
		if(not v:OnRun(time)) then
			v:Destroy()
			table.insert(delIndexList,k)
		end
	end
	self._isRunning = false

	for k=#delIndexList,1,-1 do
		table.remove(effList,delIndexList[k])
	end

	local cacheList = self._cacheList
	self._cacheList = {}
	for k,v in ipairs(cacheList) do
		if v[1] then
			self:AddEffect(v[2])
		else
			self:RemoveEffect(v[2])
		end
	end
end

function LFightIdleEffectCtrl:TimePause()
	for k,v in ipairs(self._effList) do
		v:TimePause()
	end
end

function LFightIdleEffectCtrl:TimeResume()
	for k,v in ipairs(self._effList) do
		v:TimeResume()
	end
end
-----------------------------------------------------------------
function LFightIdleEffectCtrl:Destroy()
	if self._effMaskObj then
		self._effMaskObj:Destroy()
		self._effMaskObj = nil
	end
	local effList = self._effList
	if(effList) then
		for k,v in ipairs(effList) do
			v:Destroy()
		end
		self._effList = nil
	end

	effList = self._preloadList
	if effList then
		for k,v in pairs(effList) do
			for m,n in ipairs(v) do
				n:Destroy()
			end
			v[k] = nil
		end
		self._preloadList = nil
	end


	table.removeall(self)
	self._isDestroy = true
end
-----------------------------------------------------------------
return LFightIdleEffectCtrl